var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"안녕하세요, 선생님. 절 찾으신다고 들었어요.","JPN":"こんにちは、先生。お呼びだと聞きました。","ENG":"Hello. I was told you were looking for me.","TWN":"您好，老師。聽說您找我。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"종신 계약. 네. 계약의 내용과 효력은 이해했습니다.","JPN":"終身契約。はい、契約の内容と効力は理解しました。","ENG":"A lifetime contract. Yes, I understand what it entails and how it'll affect me.","TWN":"終身契約。好的，契約的內容及效力我已經理解了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"......쉽게 정할 문제가 아니다, 그렇게 생각하세요?","JPN":"……簡単に決めていいことではない、そう思われるのですね？","ENG":"This is not an easy decision to make. Is that what you're thinking?","TWN":"……不是可以隨便決定的問題，您是這麼想的嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"전 이 날을 오랫동안 기다려 왔어요. 선생님을 찾아서 두 번 다시 헤어지지 않을 날을요.","JPN":"私、この日を長い間ずっと待っていたんです。先生を見つけて、二度と離れないようになる、そんな日を。","ENG":"I've been waiting for this day, the day that I'd never have to worry about losing you again.","TWN":"我等這一天的到來已經很久了。找到老師，並且不會再和老師分離的這一天。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"선생님께는 아주 작은 친절이었겠지만......","JPN":"先生にとっては、ほんのささやかな親切だったのかもしれませんが……","ENG":"What might have been a small act of kindness to you","TWN":"或許這對您來說只是件小事……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"썩은 물을 마시고, 쓰레기통을 뒤지던 저에겐 처음 느껴 보는 따뜻함이었어요.","JPN":"汚水を飲んで、ゴミ箱を漁っていた頃の私には、初めて感じた温もりだったんです。","ENG":"was the greatest thing that had ever happened to me, who lived on the streets, rummaging trash for food and water.","TWN":"但在過去喝著腐敗的水、翻著垃圾桶的我，第一次感受到的溫暖。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"선생님을 떠올릴 때마다 제가 느낀 감정이 어떤 건지, 동료들에게 상담했을 때......","JPN":"先生のことを思い浮かべるたびに、胸にこみ上げるこの感情は何なのか、メンバーたちに相談してみたら……","ENG":"When I talked to my teammates about my feelings toward the Teacher,","TWN":"每次一想到老師，我心中浮現的情感是什麼……當我去問同伴時……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"다들 그걸 사랑이라고 말해 줬어요.","JPN":"みんなが教えてくれました。それは恋なんだって。","ENG":"they all said they were of love.","TWN":"大家都跟我說，那就是愛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"네. 저는 선생님을 사랑하고 있었던 거에요.","JPN":"はい。私は、先生に恋していたんです。","ENG":"Yes, I'm in love with you, Teacher.","TWN":"是的。我一直愛著老師。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GAEUN_NPC_FOOLSDAY_NULL","text":{"KOREA":"그러니까...... 저를 곁에 둬 주세요.","JPN":"ですから……私を、先生のそばにいさせてください。","ENG":"So... please keep me close.","TWN":"所以……請讓我待在您身邊。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GAEUN_NPC_FOOLSDAY_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};